func (s *UserStore) GetUser(userID string) (*UserRecord, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	u, ok := s.users[userID]
	if !ok {
		return nil, false
	}
	// Return a copy to prevent race conditions
	copy := *u
	return &copy, true
}

func (s *UserStore) UpdateUser(userID string, fn func(*UserRecord)) bool {
	s.mu.Lock()
	defer s.mu.Unlock()
	u, ok := s.users[userID]
	if !ok {
		return false
	}
	fn(u)
	return true
}

func (s *UserStore) FindUserByUsername(username string) (*UserRecord, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	for _, u := range s.users {
		if strings.EqualFold(u.Username, username) {
			copy := *u
			return &copy, true
		}
	}
	return nil, false
}

