// AuthRequest is what the client sends to authenticate
type AuthRequest struct {
	Type     string `json:"type"`
	UserID   string `json:"user_id"`
	Password string `json:"password"`
	// NOTE: We intentionally do NOT accept a "role" field from the client.
	// Any client-provided role information is ignored.
	// The server determines the role from its own authoritative database.
}

